INSERT INTO `messages` VALUES (1,1,1,'client_admin','【お見積書が発行されました】\r\n税抜金額: 440,000円\r\n消費税: 44,000円\r\n税込合計: 484,000円\r\n\r\n詳細は左パネルの最新の見積書からご確認ください。\r\n\r\nご依頼いただける場合は、「設計依頼データの送付」ボタンから必須ファイル（CADデータ等）をアップロードの上、正式にご発注をお願いいたします。',NULL,NULL,'2026-06-17 10:59:24'),(2,1,6,'client_admin','【図面変更の有無報告】\n見積時から変更なし',NULL,NULL,'2026-06-17 11:03:24'),(3,1,6,'client_admin','【通知】正式依頼が受理され、すべての必要図書が揃いました。図書の内容を確認の上、一次回答期日の設定をお願いします。',NULL,NULL,'2026-06-17 11:03:24'),(4,1,1,'sub_admin','【新規発注のお知らせ】\n業務: 構造用・外皮用意匠図作図\n発注額: 16,832 円\n計算式: (50円×100㎡ + 40円×100㎡ + 30円×261.07㎡)\n\n上記の通り発注いたしました。よろしくお願いいたします。',NULL,NULL,'2026-06-17 11:05:21'),(5,1,3,'sub_admin','発注を承諾しました。完了予定日: 2026年05月21日',NULL,NULL,'2026-06-17 11:06:20'),(6,1,3,'sub_admin','【自動通知】Masaki&Yamamura 様より成果物の納品（ファイルアップロード）が行われました。\n管理者画面にて内容をご確認の上、承認（クライアントへの公開）処理を行ってください。',NULL,NULL,'2026-06-17 11:09:53'),(7,1,1,'client_admin','【通知】一次回答の基準日（期日）が 2026-06-09 に設定され、スケジュールが確定しました。左パネルのスケジュール表をご確認ください。\n\n【今後の進め方について】\n・図書の修正やご要望などがある場合は、こちらのチャットにメッセージの入力やファイルの添付をお願いいたします。\n・修正がなくそのまま進める場合は、チャット欄に「GO」とご返信ください。ご返信を確認後、申請図書一式を作成いたします。',NULL,NULL,'2026-06-17 14:10:57'),(8,1,1,'sub_admin','【自動通知】納品タスク「構造用・外皮用意匠図作図」の承認（納品完了）処理が行われました。',NULL,NULL,'2026-06-17 14:12:31'),(9,1,1,'client_admin','【本見積書が確定・発行されました】\r\n税抜金額: 440,000円\r\n消費税: 44,000円\r\n税込合計: 484,000円\r\n\r\n詳細は左パネルの最新の見積書からご確認ください。\r\n\r\n本見積内容にて確定いたしました。追って一次請求書（着手金50%）を発行いたしますので、ご確認のほどよろしくお願いいたします。',NULL,NULL,'2026-06-17 14:12:52'),(10,1,1,'client_admin','【一次請求書(50%)が発行されました】\n着手金として、本見積額の消費税加算前50%と消費税分を請求させていただきます。\n請求金額: 242,000円 (税込)\n（内訳: 税抜 220,000円、消費税 22,000円）\n\n詳細は左パネルの「一次請求書」からご確認ください。ご入金の確認後、詳細モデル作成業務に着手いたします。',NULL,NULL,'2026-06-17 14:13:32'),(11,1,1,'client_admin','【一次回答の提示 ＆ 請求書発行】\n一次回答の計算図書「A一時回答20260608.pdf」をアップロードし、一次請求書(50%)を発行いたしました。ファイル一覧（成果物）よりご確認ください。\n何卒よろしくお願いいたします。',NULL,NULL,'2026-06-17 14:13:32'),(12,1,1,'client_admin_permit','','1qQ7NBa8DfEjN4b_u2tnQL4TTi-rV44Su','pdf','2026-06-17 14:14:49'),(13,1,1,'client_admin_permit','','1-Fi14yK3pEiuhuM