CREATE TABLE `project_files` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `project_id` int(11) NOT NULL,
  `subcontractor_order_id` int(11) DEFAULT NULL,
  `file_category` varchar(100) NOT NULL,
  `file_name` varchar(255) NOT NULL,
  `drive_file_id` varchar(255) DEFAULT NULL,
  `version` int(11) NOT NULL DEFAULT 1,
  `is_latest` tinyint(1) NOT NULL DEFAULT 1,
  `is_published_to_sub` tinyint(1) DEFAULT 0,
  `created_at` datetime DEFAULT current_timestamp(),
  `update_reason` text DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `project_id` (`project_id`),
  CONSTRAINT `project_files_ibfk_1` FOREIGN KEY (`project_id`) REFERENCES `projects` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=125 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
